:root {
  --hue: 240;
  --primary: oklch(50% 0.25 var(--hue));
  --primary-light: oklch(from var(--primary) 85% c h);
  --primary-dark: oklch(from var(--primary) 30% c h);
  --text-on-primary: oklch(95% 0.02 var(--hue));
  --text-on-primary-dark: oklch(90% 0.02 var(--hue));
  --border-focus: oklch(60% 0.3 var(--hue));
}

@media (prefers-color-scheme: dark) {
  :root {
    --primary: oklch(60% 0.2 var(--hue));
    --text-on-primary: oklch(15% 0.02 var(--hue));
  }
}

@media (prefers-contrast: high) {
  :root {
    --primary: oklch(40% 0.3 var(--hue));
    --text-on-primary: oklch(98% 0.01 var(--hue));
  }
}
